      const authRes = await env.AUTH.fetch(authReq);
      if (!authRes.ok) return authRes;
      const authOut = await authRes.json();

      const transformReq = new Request(base.toString(), {
        method: "POST",
        headers: { "content-type": "application/json", "x-request-id": reqId },
        body: JSON.stringify({ ...input, ...authOut.data, stage: "transform" }),
      });
      const transformRes = await env.TRANSFORM.fetch(transformReq);
      if (!transformRes.ok) return transformRes;
      const transformOut = await transformRes.json();

